  const isUK = host.includes('amazon.co.uk');
  const isDE = host.includes('amazon.de');
  
  // Add a tiny heartbeat dot so we know the script is running
  const heartbeat = document.createElement('div');
  heartbeat.style.cssText = 'position:fixed;bottom:5px;right:5px;width:8px;height:8px;border-radius:50%;background:#28a745;z-index:9999999;opacity:0.5;pointer-events:none;';
